// Nodo: Validar y Limpiar JSON (Versión Robusta / Depuración)
const items = $input.all();
const results = [];

for (const item of items) {
  // 1. ESTRATEGIA DE BÚSQUEDA DE CONTENIDO
  // Buscamos la respuesta en todos los lugares conocidos donde Gemini/n8n suele ponerla
  let rawResponse = 
    item.json.text || 
    item.json.output || 
    item.json.content || 
    item.json.response ||
    (item.json.candidates && item.json.candidates[0]?.content?.parts?.[0]?.text);

  // Si aún es null, buscamos cualquier string largo en el objeto (último recurso)
  if (!rawResponse) {
    for (const key in item.json) {
      if (typeof item.json[key] === 'string' && item.json[key].length > 100) {
        rawResponse = item.json[key];
        break;
      }
    }
  }

  // 2. MANEJO DE ERRORES DE ENTRADA
  if (!rawResponse) {
    // Si llegamos aquí, Gemini no devolvió texto. Analizamos por qué.
    let errorMsg = 'No se encontró respuesta de Gemini.';

    // Verificar si fue bloqueado por seguridad
    if (item.json.finishReason === 'SAFETY' || item.json.finishReason === 'BLOCKOUT') {
      errorMsg = 'Gemini bloqueó la respuesta por "Safety Settings". Ve al nodo Gemini -> Options -> Safety Settings y pon todo en "Block None".';
    } else if (item.json.finishReason === 'RECITATION') {
      errorMsg = 'Gemini bloqueó la respuesta por Copyright (Recitation).';
    }

    results.push({
      json: {
        status: 'error',
        error: errorMsg,
        debug_keys_found: Object.keys(item.json), // Para que veas qué llaves llegaron
        full_input: item.json // Para depuración
      }
    });
    continue;
  }

  try {
    let cleanJson = rawResponse.toString().trim();

    // 3. LIMPIEZA DE MARKDOWN
    cleanJson = cleanJson.replace(/^```json\s*/i, '');  
    cleanJson = cleanJson.replace(/^```\s*/i, '');      
    cleanJson = cleanJson.replace(/\s*```\s*$/i, '');   
    cleanJson = cleanJson.trim();

    // 4. INTENTO DE PARSEO DIRECTO
    try {
      const parsed = JSON.parse(cleanJson);
      results.push({
        json: {
          status: 'success',
          cualificacion: parsed,
          rawResponse: rawResponse,
          wasRepaired: false
        }
      });
      continue;

    } catch (parseError) {
      // Falló el parseo directo, pasamos a reparación
    }

    // 5. REPARACIÓN DE JSON TRUNCADO
    // Buscar el último carácter de cierre válido
    const lastComma = cleanJson.lastIndexOf(',');
    const lastCloseBrace = cleanJson.lastIndexOf('}');
    const lastCloseBracket = cleanJson.lastIndexOf(']');

    // Si el final no es limpio, cortamos hasta lo seguro
    if (!cleanJson.match(/[\"\}\]]$/)) {
      const safePositions = [lastComma, lastCloseBrace, lastCloseBracket].filter(p => p > 0);
      if (safePositions.length > 0) {
        const safeCutPosition = Math.max(...safePositions);
        cleanJson = cleanJson.substring(0, safeCutPosition + 1);
      }
    }

    // Quitar coma final si existe
    cleanJson = cleanJson.replace(/,(\s*)$/, '$1');

    // Balancear llaves y corchetes
    const openBraces = (cleanJson.match(/\{/g) || []).length;
    const closeBraces = (cleanJson.match(/\}/g) || []).length;
    const openBrackets = (cleanJson.match(/\[/g) || []).length;
    const closeBrackets = (cleanJson.match(/\]/g) || []).length;

    for (let i = 0; i < (openBrackets - closeBrackets); i++) cleanJson += ']';
    for (let i = 0; i < (openBraces - closeBraces); i++) cleanJson += '}';

    const parsed = JSON.parse(cleanJson);

    results.push({
      json: {
        status: 'success',
        cualificacion: parsed,
        rawResponse: rawResponse,
        wasRepaired: true,
        warning: 'El JSON fue reparado automáticamente'
      }
    });

  } catch (error) {
    results.push({
      json: {
        status: 'error',
        error: 'Fallo al parsear JSON incluso después de reparar: ' + error.message,
        rawResponse: rawResponse
      }
    });
  }
}

return results;

const cualificacionId = $('Supabase - Insertar Cualificación').first().json.id;
