const competenciasDB = $('Supabase - Insertar Competencia').all();
const cualificacion = $('Validar y Limpiar JSON').first().json.cualificacion;
const competenciasOrig = cualificacion.competencias_especificas || [];

const codigoToId = {};
for (const c of competenciasDB) {
  codigoToId[c.json.codigo] = c.json.id;
}

const items = [];
for (const comp of competenciasOrig) {
  const competenciaId = codigoToId[comp.codigo];
  if (!competenciaId || !comp.elementos || comp.elementos.length === 0) continue;

  for (const elem of comp.elementos) {
    items.push({
      json: {
        competencia_id: competenciaId,
        numero_elemento: elem.numero,
        descripcion: elem.descripcion
      }
    });
  }
}

return items;

