const elementosDB = $('Supabase - Insertar Elementos').all();
const competenciasDB = $('Supabase - Insertar Competencia').all();
const cualificacion = $('Validar y Limpiar JSON').first().json.cualificacion;

const idToCodigo = {};
for (const c of competenciasDB) {
  idToCodigo[c.json.id] = c.json.codigo;
}

const compMap = {};
for (const comp of (cualificacion.competencias_especificas || [])) {
  compMap[comp.codigo] = comp;
}

const items = [];
for (const elem of elementosDB) {
  const elemId = elem.json.id;
  const compCodigo = idToCodigo[elem.json.competencia_id];
  if (!compCodigo) continue;

  const origComp = compMap[compCodigo];
  if (!origComp || !origComp.elementos) continue;

  const origElem = origComp.elementos.find(e => e.numero === elem.json.numero_elemento);
  if (!origElem || !origElem.criterios_desempeno) continue;

  origElem.criterios_desempeno.forEach((criterio, idx) => {
    items.push({
      json: {
        elemento_id: elemId,
        descripcion: criterio,
        orden: idx + 1
      }
    });
  });
}

return items;

