const rasDB = $('Supabase - Insertar Resultados Aprendizaje').all();
const competenciasDB = $('Supabase - Insertar Competencia').all();
const cualificacion = $('Validar y Limpiar JSON').first().json.cualificacion;

const idToCodigo = {};
for (const c of competenciasDB) {
  idToCodigo[c.json.id] = c.json.codigo;
}

const compMap = {};
for (const comp of (cualificacion.competencias_especificas || [])) {
  compMap[comp.codigo] = comp;
}

const items = [];
for (const ra of rasDB) {
  const raId = ra.json.id;
  const compCodigo = idToCodigo[ra.json.competencia_id];
  if (!compCodigo) continue;

  const origComp = compMap[compCodigo];
  if (!origComp || !origComp.resultados_aprendizaje) continue;

  const origRA = origComp.resultados_aprendizaje.find(r => r.codigo === ra.json.codigo);
  if (!origRA || !origRA.criterios_evaluacion) continue;

  origRA.criterios_evaluacion.forEach((ce, idx) => {
    items.push({
      json: {
        resultado_aprendizaje_id: raId,
        codigo: ce.codigo,
        descripcion: ce.descripcion,
        orden: idx + 1
      }
    });
  });
}

return items;

