parameters.jsCode:
const competenciasDB = $('Supabase - Insertar Competencia').all();
const cualificacion = $('Validar y Limpiar JSON').first().json.cualificacion;

const codigoToId = {};
for (const c of competenciasDB) {
  codigoToId[c.json.codigo] = c.json.id;
}

const items = [];
for (const comp of (cualificacion.competencias_especificas || [])) {
  const competenciaId = codigoToId[comp.codigo];
  if (!competenciaId || !comp.contenidos) continue;

  const contenidos = comp.contenidos;
  const fuente = contenidos.fuente || 'extraido';

  const tipos = {
    conceptual: contenidos.conceptuales || [],
    procedimental: contenidos.procedimentales || [],
    actitudinal: contenidos.actitudinales || []
  };

  for (const [tipo, lista] of Object.entries(tipos)) {
    lista.forEach((texto, idx) => {
      items.push({
        json: {
          competencia_id: competenciaId,
          tipo: tipo,
          contenido: texto,
          orden: idx + 1,
          fuente: fuente
        }
      });
    });
  }
}

return items;

